<script setup lang="ts">
import {computed,onMounted,ref} from 'vue';
import {useRouter} from 'vue-router';
import {ArrowLeft,BookOpen,CheckCircle2,FileText,FolderPlus,Plus,Search,Trash2,UploadCloud,X,XCircle} from 'lucide-vue-next';
import {api} from '../api';
import {appDialog} from '../components/appDialog';

type KB={id:number,name:string,description:string,color:string,documents:number,icon:string,favorite:boolean,archived:boolean,sortOrder:number,role:string};
type Doc={id:number,fileName:string,size:number,status:string,segmentCount:number,errorMessage?:string};
const router=useRouter(),bases=ref<KB[]>([]),selected=ref<KB>(),docs=ref<Doc[]>([]),query=ref(''),showCreate=ref(false),pendingDeleteBase=ref<KB>(),deletingBase=ref(false),uploading=ref(false),uploadProgress=ref({done:0,total:0});
const form=ref({name:'',description:'',color:'#7157F6'});
const filtered=computed(()=>bases.value.filter(k=>!k.archived&&k.name.toLowerCase().includes(query.value.toLowerCase())));
const totalDocs=computed(()=>bases.value.reduce((sum,k)=>sum+k.documents,0));
function errorText(error:any,fallback:string){return error.response?.data?.message||error.response?.data?.detail||fallback}

async function load(){bases.value=(await api.get('/knowledge-bases')).data;const current=selected.value&&bases.value.find(k=>k.id===selected.value!.id);if(current)await select(current);else if(filtered.value[0])await select(filtered.value[0]);else{selected.value=undefined;docs.value=[]}}
async function select(base:KB){selected.value=base;docs.value=(await api.get(`/knowledge-bases/${base.id}/documents`)).data}
async function create(){try{const{data}=await api.post('/knowledge-bases',form.value);showCreate.value=false;form.value={name:'',description:'',color:'#7157F6'};await load();const created=bases.value.find(k=>k.id===data.id);if(created)await select(created)}catch(error:any){await appDialog.alert({title:'创建失败',message:errorText(error,'无法创建知识库，请稍后重试。')})}}
async function uploadMany(e:Event){const input=e.target as HTMLInputElement,files=Array.from(input.files||[]);if(!files.length||!selected.value)return;uploading.value=true;uploadProgress.value={done:0,total:files.length};let failed=0;try{for(const file of files){const data=new FormData();data.append('file',file);try{await api.post(`/knowledge-bases/${selected.value.id}/documents`,data)}catch{failed++}finally{uploadProgress.value.done++}}await load();await appDialog.alert({title:failed?'上传部分完成':'上传完成',message:failed?`${files.length-failed} 个文件上传成功，${failed} 个文件处理失败。`:`${files.length} 个文件已上传并提交处理。`})}finally{uploading.value=false;input.value=''}}
async function removeDocument(doc:Doc){if(!await appDialog.confirm({title:'删除知识文档',message:`“${doc.fileName}”及其全部向量片段将被永久删除。`,confirmText:'删除文档',danger:true}))return;try{await api.delete(`/documents/${doc.id}`);await load();await appDialog.alert({title:'删除成功',message:`文档“${doc.fileName}”已删除。`})}catch(error:any){await appDialog.alert({title:'删除失败',message:errorText(error,'无法删除该文档。')})}}
function requestRemoveBase(base:KB){deletingBase.value=false;pendingDeleteBase.value=base}
async function confirmRemoveBase(){const base=pendingDeleteBase.value;if(!base||deletingBase.value)return;deletingBase.value=true;try{await api.delete(`/knowledge-bases/${base.id}`);pendingDeleteBase.value=undefined;deletingBase.value=false;if(selected.value?.id===base.id)selected.value=undefined;await load();void appDialog.alert({title:'删除成功',message:`知识库“${base.name}”已删除。`})}catch(error:any){pendingDeleteBase.value=undefined;deletingBase.value=false;void appDialog.alert({title:'删除失败',message:errorText(error,'无法删除该知识库，请检查当前账号权限。')})}}
onMounted(load);
</script>

<template><main class="knowledge-page"><header class="page-header"><button type="button" class="back" @click="router.push('/')"><ArrowLeft/>返回工作台</button><div><span class="eyebrow">KNOWLEDGE MANAGEMENT</span><h1>知识库管理</h1><p>为每个知识库批量上传并维护文档，系统会自动完成切片和向量化。</p></div><button type="button" class="primary" @click="showCreate=true"><Plus/>新建知识库</button></header>
  <section class="summary"><div><BookOpen/><span><b>{{bases.length}}</b><small>知识库</small></span></div><div><FileText/><span><b>{{totalDocs}}</b><small>知识文档</small></span></div><div><CheckCircle2/><span><b>{{docs.filter(d=>d.status==='READY').length}}</b><small>当前库已向量化</small></span></div></section>
  <div class="management-layout"><aside class="base-panel"><div class="panel-title"><b>知识库</b><span>{{filtered.length}}</span></div><div class="base-search"><Search/><input v-model="query" placeholder="搜索知识库"></div><div class="base-list"><div v-for="base in filtered" :key="base.id" :class="{active:selected?.id===base.id}" role="button" tabindex="0" @click="select(base)" @keydown.enter="select(base)"><span class="base-icon" :style="{background:`${base.color}18`,color:base.color}">{{base.icon||'📚'}}</span><span><b>{{base.name}}</b><small>{{base.documents}} 个文档 · {{base.role}}</small></span><button v-if="base.role==='OWNER'" type="button" class="base-delete" title="删除知识库" @click.stop.prevent="requestRemoveBase(base)"><Trash2/></button></div><button v-if="!filtered.length&&!query" type="button" class="empty-bases create-empty" @click="showCreate=true"><FolderPlus/><b>新建知识库</b><span>创建后即可批量上传文档</span></button><div v-else-if="!filtered.length" class="empty-bases"><Search/>没有匹配的知识库</div></div></aside>
    <section class="document-panel"><template v-if="selected"><header><div><span class="library-mark" :style="{background:`${selected.color}18`,color:selected.color}">{{selected.icon||'📚'}}</span><div><h2>{{selected.name}}</h2><p>{{selected.description||'暂无描述'}} · {{docs.length}} 个文档</p></div></div></header><label v-if="selected.role!=='VIEWER'" class="batch-upload" :class="{uploading}"><UploadCloud/><b>{{uploading?`正在处理 ${uploadProgress.done}/${uploadProgress.total}`:'批量上传文档'}}</b><span>可一次选择多个 PDF、Word、PPT、TXT 或 Markdown 文件</span><input type="file" multiple accept=".pdf,.doc,.docx,.ppt,.pptx,.txt,.md" :disabled="uploading" @change="uploadMany"><i v-if="uploading" :style="{width:`${uploadProgress.total?uploadProgress.done/uploadProgress.total*100:0}%`}"></i></label><div class="doc-table"><div class="doc-head"><span>文件名称</span><span>大小</span><span>切片</span><span>状态</span><span>操作</span></div><article v-for="doc in docs" :key="doc.id"><span class="doc-name"><FileText/><b>{{doc.fileName}}</b></span><span>{{(doc.size/1024).toFixed(1)}} KB</span><span>{{doc.segmentCount}}</span><span class="doc-status" :class="doc.status.toLowerCase()"><CheckCircle2 v-if="doc.status==='READY'"/><XCircle v-else/>{{doc.status}}</span><button v-if="selected.role!=='VIEWER'" title="删除文档" @click="removeDocument(doc)"><Trash2/></button></article><div v-if="!docs.length" class="empty-docs"><FileText/><b>还没有知识文档</b><span>使用上方区域一次上传一个或多个文件</span></div></div></template><div v-else class="select-empty"><BookOpen/><h2>创建第一个知识库</h2><p>知识库用于组织一组相关文档，并为 AI 问答提供检索内容。</p><button class="primary" @click="showCreate=true"><Plus/>新建知识库</button></div></section>
  </div>
  <div v-if="showCreate" class="modal-backdrop" @click.self="showCreate=false"><form class="modal" @submit.prevent="create"><button type="button" class="modal-close" @click="showCreate=false"><X/></button><span class="eyebrow">NEW KNOWLEDGE BASE</span><h2>新建知识库</h2><label>知识库名称<input v-model="form.name" required placeholder="例如：产品研发资料"></label><label>描述<textarea v-model="form.description" placeholder="说明该知识库包含的内容"></textarea></label><label>主题颜色<input v-model="form.color" type="color"></label><button class="primary">创建知识库</button></form></div>
  <div v-if="pendingDeleteBase" class="modal-backdrop" @click.self="pendingDeleteBase=undefined"><section class="delete-modal"><span class="delete-icon"><Trash2/></span><h2>删除知识库</h2><p>知识库“{{pendingDeleteBase.name}}”中的 <b>{{pendingDeleteBase.documents}}</b> 个文档、向量和配置都会被永久删除，此操作无法恢复。</p><div><button type="button" class="cancel-delete" :disabled="deletingBase" @click="pendingDeleteBase=undefined">取消</button><button type="button" class="confirm-delete" :disabled="deletingBase" @click="confirmRemoveBase">{{deletingBase?'正在删除…':'永久删除'}}</button></div></section></div>
</main></template>

<style scoped>
.create-empty{width:100%;border:1px dashed #d7cfdf;border-radius:13px;background:#fff;color:#756a7d;cursor:pointer}.create-empty:hover{border-color:#8f7ccb;background:#f5f1fa;color:#6754ad}.create-empty b,.create-empty span{display:block}.create-empty span{margin-top:4px;font-size:9px;color:#9e96a4}
.delete-modal{width:min(430px,92vw);padding:30px;border-radius:20px;background:#fff;text-align:center;box-shadow:0 28px 90px #2d203a35}.delete-icon{width:52px;height:52px;margin:auto;border-radius:16px;background:#fff0f2;color:#c84d62;display:grid;place-items:center}.delete-icon svg{width:22px}.delete-modal h2{margin:14px 0 8px}.delete-modal p{margin:0;color:#807985;font-size:13px;line-height:1.7}.delete-modal>div{display:flex;justify-content:center;gap:10px;margin-top:24px}.delete-modal button{min-width:100px;border:0;border-radius:10px;padding:11px;font-weight:600}.cancel-delete{background:#f1eef4;color:#67606c}.confirm-delete{background:#c94c61;color:#fff}.delete-modal button:disabled{opacity:.55}
.base-list>div{width:100%;border:0;border-radius:12px;background:transparent;padding:9px 7px;display:flex;align-items:center;gap:9px;text-align:left;color:#514b57;cursor:pointer}.base-list>div:hover,.base-list>div.active{background:#eee9f5}.base-list>div>span:nth-child(2){min-width:0;flex:1;display:flex;flex-direction:column}
.knowledge-page{min-height:100vh;padding:32px clamp(22px,4vw,64px);background:radial-gradient(circle at 84% 0,#eee9ff,transparent 25%),#f8f7fb;color:#37323f}.page-header{max-width:1320px;margin:auto;display:grid;grid-template-columns:180px 1fr auto;align-items:center}.back{border:0;background:transparent;color:#716a7b;display:flex;align-items:center;gap:7px}.back svg{width:18px}.page-header h1{margin:5px 0;font-size:32px}.page-header p{margin:0;color:#8c8592;font-size:13px}.summary{max-width:1320px;margin:26px auto 14px;display:flex;gap:10px}.summary>div{min-width:165px;padding:13px 16px;border:1px solid #e8e3ed;border-radius:14px;background:#fff;display:flex;align-items:center;gap:11px}.summary svg{width:19px;color:#725fc0}.summary span{display:flex;flex-direction:column}.summary b{font-size:18px}.summary small{color:#968f9c;font-size:9px}.management-layout{max-width:1320px;height:calc(100vh - 220px);min-height:560px;margin:auto;display:grid;grid-template-columns:300px 1fr;border:1px solid #e7e2eb;border-radius:20px;background:#fff;box-shadow:0 18px 55px #4534530c;overflow:hidden}.base-panel{padding:18px 12px;background:#faf9fc;border-right:1px solid #ebe7ef;overflow:auto}.panel-title{padding:0 8px 12px;display:flex;justify-content:space-between}.panel-title span{color:#9b94a0}.base-search{height:38px;padding:0 10px;border:1px solid #e5e0e9;border-radius:10px;background:#fff;display:flex;align-items:center}.base-search svg{width:14px;color:#918a97}.base-search input{width:100%;border:0;outline:0;padding-left:8px}.base-list{margin-top:10px}.base-list>button{width:100%;border:0;border-radius:12px;background:transparent;padding:9px 7px;display:flex;align-items:center;gap:9px;text-align:left;color:#514b57}.base-list>button:hover,.base-list>button.active{background:#eee9f5}.base-icon{width:35px;height:35px;border-radius:10px;display:grid;place-items:center}.base-list>button>span:nth-child(2){min-width:0;flex:1;display:flex;flex-direction:column}.base-list b{font-size:11px;white-space:nowrap;overflow:hidden;text-overflow:ellipsis}.base-list small{margin-top:2px;color:#98919e;font-size:9px}.base-delete{border:0;background:transparent;color:#b76473;padding:5px}.base-delete svg{width:14px}.empty-bases{padding:50px 10px;text-align:center;color:#a19aa6}.empty-bases svg{display:block;margin:0 auto 8px}.document-panel{padding:25px;overflow:auto}.document-panel>header>div{display:flex;align-items:center;gap:12px}.library-mark{width:48px;height:48px;border-radius:14px;display:grid;place-items:center;font-size:20px}.document-panel h2{margin:0}.document-panel header p{margin:5px 0 0;color:#938c98;font-size:11px}.batch-upload{position:relative;height:130px;margin:22px 0;border:1.5px dashed #cfc6dd;border-radius:16px;background:#faf8fd;display:flex;align-items:center;justify-content:center;flex-direction:column;gap:6px;color:#675f6d;cursor:pointer;overflow:hidden}.batch-upload:hover{border-color:#8e7dcb;background:#f7f3fc}.batch-upload svg{color:#735fc1}.batch-upload span{color:#9b94a0;font-size:10px}.batch-upload input{display:none}.batch-upload i{position:absolute;left:0;bottom:0;height:4px;background:#7562c8;transition:.25s}.doc-head,.doc-table article{display:grid;grid-template-columns:minmax(240px,2fr) 100px 70px 110px 45px;align-items:center;gap:12px}.doc-head{padding:9px 12px;background:#faf9fc;color:#9b94a0;font-size:9px;font-weight:700}.doc-table article{min-height:58px;padding:9px 12px;border-bottom:1px solid #f0edf2;color:#77707d;font-size:10px}.doc-name{display:flex;align-items:center;gap:9px;min-width:0}.doc-name svg{width:17px;color:#7562c8}.doc-name b{color:#4a444f;white-space:nowrap;overflow:hidden;text-overflow:ellipsis}.doc-status{display:flex;align-items:center;gap:5px}.doc-status svg{width:13px}.doc-status.ready{color:#438367}.doc-status.failed{color:#c34f63}.doc-table article>button{border:0;background:#fff0f2;color:#bf5062;border-radius:8px;padding:7px;display:grid;place-items:center}.doc-table article>button svg{width:14px}.empty-docs,.select-empty{padding:80px 20px;text-align:center;color:#9c95a1;display:flex;align-items:center;flex-direction:column}.empty-docs svg,.select-empty svg{width:34px;margin-bottom:10px;color:#b0a6bf}.empty-docs b{color:#645e69}.empty-docs span{margin-top:5px;font-size:10px}.select-empty h2{margin:7px}.select-empty p{max-width:420px}.select-empty .primary{margin-top:14px}.modal>.primary{width:100%;margin-top:24px}@media(max-width:850px){.page-header{grid-template-columns:1fr;gap:16px}.page-header>.primary{justify-self:start}.summary{overflow:auto}.management-layout{height:auto;min-height:0;grid-template-columns:1fr}.base-panel{max-height:280px;border-right:0;border-bottom:1px solid #ebe7ef}.doc-head{display:none}.doc-table article{grid-template-columns:1fr 45px}.doc-table article>span:not(.doc-name):not(.doc-status){display:none}.doc-status{display:none}}
</style>
